8628       return {SPF_UNKNOWN, SPNB_NA, false};
8629   }
8630 
8631   SelectPatternNaNBehavior NaNBehavior = SPNB_NA;
8632   bool Ordered = false;
8633 
8634   // When given one NaN and one non-NaN input:
8635   //   - maxnum/minnum (C99 fmaxf()/fminf()) return the non-NaN input.
8636   //   - A simple C99 (a < b ? a : b) construction will return 'b' (as the
8637   //     ordered comparison fails), which could be NaN or non-NaN.
8638   // so here we discover exactly what NaN behavior is required/accepted.
8639   if (CmpInst::isFPPredicate(Pred)) {
8640     bool LHSSafe = isKnownNonNaN(CmpLHS, FMF);
8641     bool RHSSafe = isKnownNonNaN(CmpRHS, FMF);
8642 
8643     if (LHSSafe && RHSSafe) {
8644       // Both operands are known non-NaN.
8645       NaNBehavior = SPNB_RETURNS_ANY;
8646     } else if (CmpInst::isOrdered(Pred)) {
8647       // An ordered comparison will return false when given a NaN, so it
8648       // returns the RHS.
8649       Ordered = true;
8650       if (LHSSafe)
8651         // LHS is non-NaN, so if RHS is NaN then NaN will be returned.
8652         NaNBehavior = SPNB_RETURNS_NAN;
8653       else if (RHSSafe)
8654         NaNBehavior = SPNB_RETURNS_OTHER;
8655       else
8656         // Completely unsafe.
8657         return {SPF_UNKNOWN, SPNB_NA, false};
8658     } else {
8659       Ordered = false;
8660       // An unordered comparison will return true when given a NaN, so it
8661       // returns the LHS.
8662       if (LHSSafe)
8663         // LHS is non-NaN, so if RHS is NaN then non-NaN will be returned.
8664         NaNBehavior = SPNB_RETURNS_OTHER;
8665       else if (RHSSafe)
8666         NaNBehavior = SPNB_RETURNS_NAN;
8667       else
8668         // Completely unsafe.
8669         return {SPF_UNKNOWN, SPNB_NA, false};
8670     }
8671   }
8672 
8673   if (TrueVal == CmpRHS && FalseVal == CmpLHS) {
8674     std::swap(CmpLHS, CmpRHS);
8675     Pred = CmpInst::getSwappedPredicate(Pred);
8676     if (NaNBehavior == SPNB_RETURNS_NAN)
8677       NaNBehavior = SPNB_RETURNS_OTHER;
8678     else if (NaNBehavior == SPNB_RETURNS_OTHER)
8679       NaNBehavior = SPNB_RETURNS_NAN;
8680     Ordered = !Ordered;
8681   }
8682 
8683   // ([if]cmp X, Y) ? X : Y
8684   if (TrueVal == CmpLHS && FalseVal == CmpRHS)
8685     return getSelectPattern(Pred, NaNBehavior, Ordered);
8686 
8687   if (isKnownNegation(TrueVal, FalseVal)) {
8688     // Sign-extending LHS does not change its sign, so TrueVal/FalseVal can
8689     // match against either LHS or sext(LHS).
8690     auto MaybeSExtCmpLHS =
8691         m_CombineOr(m_Specific(CmpLHS), m_SExt(m_Specific(CmpLHS)));
8692     auto ZeroOrAllOnes = m_CombineOr(m_ZeroInt(), m_AllOnes());
8693     auto ZeroOrOne = m_CombineOr(m_ZeroInt(), m_One());
8694     if (match(TrueVal, MaybeSExtCmpLHS)) {
8695       // Set the return values. If the compare uses the negated value (-X >s 0),
8696       // swap the return values because the negated value is always 'RHS'.
8697       LHS = TrueVal;
8698       RHS = FalseVal;
8699       if (match(CmpLHS, m_Neg(m_Specific(FalseVal))))
8700         std::swap(LHS, RHS);
8701 
8702       // (X >s 0) ? X : -X or (X >s -1) ? X : -X --> ABS(X)
8703       // (-X >s 0) ? -X : X or (-X >s -1) ? -X : X --> ABS(X)
8704       if (Pred == ICmpInst::ICMP_SGT && match(CmpRHS, ZeroOrAllOnes))
8705         return {SPF_ABS, SPNB_NA, false};
8706 
8707       // (X >=s 0) ? X : -X or (X >=s 1) ? X : -X --> ABS(X)
8708       if (Pred == ICmpInst::ICMP_SGE && match(CmpRHS, ZeroOrOne))
8709         return {SPF_ABS, SPNB_NA, false};
8710 
8711       // (X <s 0) ? X : -X or (X <s 1) ? X : -X --> NABS(X)
8712       // (-X <s 0) ? -X : X or (-X <s 1) ? -X : X --> NABS(X)
8713       if (Pred == ICmpInst::ICMP_SLT && match(CmpRHS, ZeroOrOne))
8714         return {SPF_NABS, SPNB_NA, false};
8715     }
8716     else if (match(FalseVal, MaybeSExtCmpLHS)) {
8717       // Set the return values. If the compare uses the negated value (-X >s 0),
8718       // swap the return values because the negated value is always 'RHS'.
8719       LHS = FalseVal;
8720       RHS = TrueVal;
8721       if (match(CmpLHS, m_Neg(m_Specific(TrueVal))))
8722         std::swap(LHS, RHS);
8723 
8724       // (X >s 0) ? -X : X or (X >s -1) ? -X : X --> NABS(X)
8725       // (-X >s 0) ? X : -X or (-X >s -1) ? X : -X --> NABS(X)
8726       if (Pred == ICmpInst::ICMP_SGT && match(CmpRHS, ZeroOrAllOnes))
8727         return {SPF_NABS, SPNB_NA, false};
8728 
8729       // (X <s 0) ? -X : X or (X <s 1) ? -X : X --> ABS(X)
8730       // (-X <s 0) ? X : -X or (-X <s 1) ? X : -X --> ABS(X)
8731       if (Pred == ICmpInst::ICMP_SLT && match(CmpRHS, ZeroOrOne))
8732         return {SPF_ABS, SPNB_NA, false};
8733     }
8734   }
8735 
8736   if (CmpInst::isIntPredicate(Pred))
8737     return matchMinMax(Pred, CmpLHS, CmpRHS, TrueVal, FalseVal, LHS, RHS, Depth);
8738 
8739   // According to (IEEE 754-2008 5.3.1), minNum(0.0, -0.0) and similar
8740   // may return either -0.0 or 0.0, so fcmp/select pair has stricter
8741   // semantics than minNum. Be conservative in such case.
8742   if (NaNBehavior != SPNB_RETURNS_ANY ||
8743       (!FMF.noSignedZeros() && !isKnownNonZero(CmpLHS) &&
8744        !isKnownNonZero(CmpRHS)))
8745     return {SPF_UNKNOWN, SPNB_NA, false};
8746 
8747   return matchFastFloatClamp(Pred, CmpLHS, CmpRHS, TrueVal, FalseVal, LHS, RHS);
8748 }
