1277 /// We can't replace %sel with %add unless we strip away the flags.
1278 /// TODO: Wrapping flags could be preserved in some cases with better analysis.
1279 Instruction *InstCombinerImpl::foldSelectValueEquivalence(SelectInst &Sel,
1280                                                           CmpInst &Cmp) {
1281   // Canonicalize the pattern to an equivalence on the predicate by swapping the
1282   // select operands.
1283   Value *TrueVal = Sel.getTrueValue(), *FalseVal = Sel.getFalseValue();
1284   bool Swapped = false;
1285   if (Cmp.isEquivalence(/*Invert=*/true)) {
1286     std::swap(TrueVal, FalseVal);
1287     Swapped = true;
1288   } else if (!Cmp.isEquivalence()) {
1289     return nullptr;
1290   }
1291 
1292   Value *CmpLHS = Cmp.getOperand(0), *CmpRHS = Cmp.getOperand(1);
1293   auto ReplaceOldOpWithNewOp = [&](Value *OldOp,
1294                                    Value *NewOp) -> Instruction * {
1295     // In X == Y ? f(X) : Z, try to evaluate f(Y) and replace the operand.
1296     // Take care to avoid replacing X == Y ? X : Z with X == Y ? Y : Z, as that
1297     // would lead to an infinite replacement cycle.
1298     // If we will be able to evaluate f(Y) to a constant, we can allow undef,
1299     // otherwise Y cannot be undef as we might pick different values for undef
1300     // in the cmp and in f(Y).
1301     if (TrueVal == OldOp && (isa<Constant>(OldOp) || !isa<Constant>(NewOp)))
1302       return nullptr;
1303 
1304     if (Value *V = simplifyWithOpReplaced(TrueVal, OldOp, NewOp, SQ,
1305                                           /* AllowRefinement=*/true)) {
1306       // Need some guarantees about the new simplified op to ensure we don't inf
1307       // loop.
1308       // If we simplify to a constant, replace if we aren't creating new undef.
1309       if (match(V, m_ImmConstant()) &&
1310           isGuaranteedNotToBeUndef(V, SQ.AC, &Sel, &DT))
1311         return replaceOperand(Sel, Swapped ? 2 : 1, V);
1312 
1313       // If NewOp is a constant and OldOp is not replace iff NewOp doesn't
1314       // contain and undef elements.
1315       if (match(NewOp, m_ImmConstant()) || NewOp == V) {
1316         if (isGuaranteedNotToBeUndef(NewOp, SQ.AC, &Sel, &DT))
1317           return replaceOperand(Sel, Swapped ? 2 : 1, V);
1318         return nullptr;
1319       }
1320     }
1321 
1322     // Even if TrueVal does not simplify, we can directly replace a use of
1323     // CmpLHS with CmpRHS, as long as the instruction is not used anywhere
1324     // else and is safe to speculatively execute (we may end up executing it
1325     // with different operands, which should not cause side-effects or trigger
1326     // undefined behavior). Only do this if CmpRHS is a constant, as
1327     // profitability is not clear for other cases.
1328     if (OldOp == CmpLHS && match(NewOp, m_ImmConstant()) &&
1329         !match(OldOp, m_Constant()) &&
1330         isGuaranteedNotToBeUndef(NewOp, SQ.AC, &Sel, &DT))
1331       if (replaceInInstruction(TrueVal, OldOp, NewOp))
1332         return &Sel;
1333     return nullptr;
1334   };
1335 
1336   if (Instruction *R = ReplaceOldOpWithNewOp(CmpLHS, CmpRHS))
1337     return R;
1338   if (Instruction *R = ReplaceOldOpWithNewOp(CmpRHS, CmpLHS))
1339     return R;
1340 
1341   auto *FalseInst = dyn_cast<Instruction>(FalseVal);
1342   if (!FalseInst)
1343     return nullptr;
1344 
1345   // InstSimplify already performed this fold if it was possible subject to
1346   // current poison-generating flags. Check whether dropping poison-generating
1347   // flags enables the transform.
1348 
1349   // Try each equivalence substitution possibility.
1350   // We have an 'EQ' comparison, so the select's false value will propagate.
1351   // Example:
1352   // (X == 42) ? 43 : (X + 1) --> (X == 42) ? (X + 1) : (X + 1) --> X + 1
1353   SmallVector<Instruction *> DropFlags;
1354   if (simplifyWithOpReplaced(FalseVal, CmpLHS, CmpRHS, SQ,
1355                              /* AllowRefinement */ false,
1356                              &DropFlags) == TrueVal ||
1357       simplifyWithOpReplaced(FalseVal, CmpRHS, CmpLHS, SQ,
1358                              /* AllowRefinement */ false,
1359                              &DropFlags) == TrueVal) {
1360     for (Instruction *I : DropFlags) {
1361       I->dropPoisonGeneratingAnnotations();
